import React, { useState, useEffect } from 'react';
import { admin, cities } from '../utils/api';
import MapPicker from '../components/MapPicker';

const AdminDashboard = () => {
  const [places, setPlaces] = useState([]);
  const [cityList, setCityList] = useState([]);
  const [selectedCityFilter, setSelectedCityFilter] = useState('ALL');
  const [selectedTypeFilter, setSelectedTypeFilter] = useState('ALL');
  const [filteredPlaces, setFilteredPlaces] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [editingPlace, setEditingPlace] = useState(null);
  const [formData, setFormData] = useState({
    city_id: '',
    name: '',
    type: 'HOTEL',
    description: '',
    price: '',
    rating: '',
    latitude: '',
    longitude: '',
    image: null
  });

  useEffect(() => {
    fetchPlaces();
    fetchCities();
  }, []);

  useEffect(() => {
    let filtered = places;

    if (selectedCityFilter !== 'ALL') {
      filtered = filtered.filter(place => place.city_id == selectedCityFilter);
    }

    if (selectedTypeFilter !== 'ALL') {
      filtered = filtered.filter(place => place.type === selectedTypeFilter);
    }

    setFilteredPlaces(filtered);
  }, [places, selectedCityFilter, selectedTypeFilter]);

  const fetchPlaces = async () => {
    try {
      const response = await admin.getPlaces();
      setPlaces(response.data);
    } catch (error) {
      console.error('Failed to fetch places:', error);
    }
  };

  const fetchCities = async () => {
    try {
      const response = await cities.getAll();
      setCityList(response.data);
    } catch (error) {
      console.error('Failed to fetch cities:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Check required fields
    if (!formData.city_id || !formData.name || !formData.type || !formData.price || !formData.latitude || !formData.longitude) {
      alert('Please fill all required fields and select location on map');
      return;
    }

    try {
      const { rating, ...placeData } = formData; // Remove rating from submission
      console.log('Sending data:', placeData); // Debug log

      if (editingPlace) {
        await admin.updatePlace(editingPlace.id, placeData);
      } else {
        await admin.addPlace(placeData);
      }

      fetchPlaces();
      resetForm();
    } catch (error) {
      console.error('Failed to save place:', error);
      console.error('Error response:', error.response?.data); // More detailed error
      alert('Failed to save place: ' + (error.response?.data?.message || error.message));
    }
  };

  const handleEdit = (place) => {
    setEditingPlace(place);
    setFormData({
      city_id: place.city_id,
      name: place.name,
      type: place.type,
      description: place.description,
      price: place.price,
      latitude: place.latitude,
      longitude: place.longitude
    });
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this place?')) {
      try {
        await admin.deletePlace(id);
        fetchPlaces();
      } catch (error) {
        console.error('Failed to delete place:', error);
      }
    }
  };

  const handleLocationSelect = (lat, lng) => {
    setFormData({
      ...formData,
      latitude: lat,
      longitude: lng
    });
  };

  const resetForm = () => {
    setFormData({
      city_id: '',
      name: '',
      type: 'HOTEL',
      description: '',
      price: '',
      latitude: '',
      longitude: '',
      image: null
    });
    setEditingPlace(null);
    setShowForm(false);
  };

  const getTypeColor = (type) => {
    switch (type) {
      case 'HOTEL': return '#3b82f6';
      case 'RESTAURANT': return '#ef4444';
      case 'ATTRACTION': return '#10b981';
      default: return '#6b7280';
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h2 style={styles.title}>Admin Dashboard</h2>
        <div style={styles.headerActions}>
          <select 
            value={selectedCityFilter} 
            onChange={(e) => setSelectedCityFilter(e.target.value)}
            style={styles.filterSelect}
          >
            <option value="ALL">All Cities</option>
            {cityList.map(city => (
              <option key={city.id} value={city.id}>{city.name}</option>
            ))}
          </select>
          <select 
            value={selectedTypeFilter} 
            onChange={(e) => setSelectedTypeFilter(e.target.value)}
            style={styles.filterSelect}
          >
            <option value="ALL">All Types</option>
            <option value="HOTEL">Hotels</option>
            <option value="RESTAURANT">Restaurants</option>
            <option value="ATTRACTION">Attractions</option>
          </select>
          <button 
            onClick={() => setShowForm(!showForm)} 
            style={styles.addButton}
          >
            {showForm ? 'Cancel' : 'Add New Place'}
          </button>
        </div>
      </div>

      {showForm && (
        <div style={styles.formContainer}>
          <h3>{editingPlace ? 'Edit Place' : 'Add New Place'}</h3>
          <form onSubmit={handleSubmit} style={styles.form}>
            <div style={styles.formRow}>
              <div style={styles.formField}>
                <label style={styles.label}>City:</label>
                <select
                  value={formData.city_id}
                  onChange={(e) => setFormData({...formData, city_id: e.target.value})}
                  style={styles.input}
                  required
                >
                  <option value="">Select City</option>
                  {cityList.map(city => (
                    <option key={city.id} value={city.id}>{city.name}</option>
                  ))}
                </select>
              </div>

              <div style={styles.formField}>
                <label style={styles.label}>Type:</label>
                <select
                  value={formData.type}
                  onChange={(e) => setFormData({...formData, type: e.target.value})}
                  style={styles.input}
                  required
                >
                  <option value="HOTEL">Hotel</option>
                  <option value="RESTAURANT">Restaurant</option>
                  <option value="ATTRACTION">Attraction</option>
                </select>
              </div>
            </div>

            <div style={styles.formField}>
              <label style={styles.label}>Name:</label>
              <input
                type="text"
                value={formData.name}
                onChange={(e) => setFormData({...formData, name: e.target.value})}
                style={styles.input}
                required
              />
            </div>

            <div style={styles.formField}>
              <label style={styles.label}>Description:</label>
              <textarea
                value={formData.description}
                onChange={(e) => setFormData({...formData, description: e.target.value})}
                style={styles.textarea}
                rows="3"
              />
            </div>

            <div style={styles.formField}>
              <label style={styles.label}>Upload Image:</label>
              <input
                type="file"
                accept="image/*"
                onChange={(e) => setFormData({...formData, image: e.target.files[0]})}
                style={styles.fileInput}
              />
              {formData.image && (
                <div style={styles.imagePreview}>
                  <img 
                    src={URL.createObjectURL(formData.image)} 
                    alt="Preview" 
                    style={styles.previewImage}
                  />
                </div>
              )}
            </div>

            <div style={styles.formField}>
              <label style={styles.label}>Select Location on Map:</label>
              <MapPicker 
                onLocationSelect={handleLocationSelect}
                initialLat={parseFloat(formData.latitude) || 27.7172}
                initialLng={parseFloat(formData.longitude) || 85.3240}
                selectedCityId={formData.city_id}
              />
            </div>

            <div style={styles.formRow}>
              <div style={styles.formField}>
                <label style={styles.label}>Price (NPR):</label>
                <input
                  type="number"
                  step="0.01"
                  value={formData.price}
                  onChange={(e) => setFormData({...formData, price: e.target.value})}
                  style={styles.input}
                  required
                />
              </div>
            </div>

            <div style={styles.formRow}>
              <div style={styles.formField}>
                <label style={styles.label}>Latitude (Auto-filled):</label>
                <input
                  type="number"
                  step="any"
                  value={formData.latitude}
                  onChange={(e) => setFormData({...formData, latitude: e.target.value})}
                  style={{...styles.input, backgroundColor: '#f3f4f6'}}
                  readOnly
                />
              </div>

              <div style={styles.formField}>
                <label style={styles.label}>Longitude (Auto-filled):</label>
                <input
                  type="number"
                  step="any"
                  value={formData.longitude}
                  onChange={(e) => setFormData({...formData, longitude: e.target.value})}
                  style={{...styles.input, backgroundColor: '#f3f4f6'}}
                  readOnly
                />
              </div>
            </div>

            <div style={styles.formActions}>
              <button type="submit" style={styles.saveButton}>
                {editingPlace ? 'Update Place' : 'Add Place'}
              </button>
              <button type="button" onClick={resetForm} style={styles.cancelButton}>
                Cancel
              </button>
            </div>
          </form>
        </div>
      )}

      <div style={styles.placesContainer}>
        <div style={styles.placesHeader}>
          <h3 style={styles.placesTitle}>All Places ({filteredPlaces.length} found)</h3>
        </div>
        <div style={styles.tableContainer}>
          <table style={styles.table}>
            <thead>
              <tr style={styles.tableHeader}>
                <th style={styles.th}>Image</th>
                <th style={styles.th}>Name</th>
                <th style={styles.th}>Type</th>
                <th style={styles.th}>City</th>
                <th style={styles.th}>Description</th>
                <th style={styles.th}>Price (NPR)</th>
                <th style={styles.th}>Rating</th>
                <th style={styles.th}>Location</th>
                <th style={styles.th}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredPlaces.map(place => (
                <tr key={place.id} style={styles.tableRow}>
                  <td style={styles.td}>
                    <div style={styles.imagePlaceholder}>
                      📷
                    </div>
                  </td>
                  <td style={styles.td}>
                    <strong>{place.name}</strong>
                  </td>
                  <td style={styles.td}>
                    <span style={{...styles.typeTag, backgroundColor: getTypeColor(place.type)}}>
                      {place.type}
                    </span>
                  </td>
                  <td style={styles.td}>{place.city_name}</td>
                  <td style={styles.td}>
                    <div style={styles.descriptionCell}>
                      {place.description}
                    </div>
                  </td>
                  <td style={styles.td}>
                    <strong style={styles.price}>NPR {place.price}</strong>
                  </td>
                  <td style={styles.td}>
                    <span style={styles.rating}>★ {place.rating}</span>
                  </td>
                  <td style={styles.td}>
                    <div style={styles.coordinates}>
                      {place.latitude.toFixed(4)}, {place.longitude.toFixed(4)}
                    </div>
                  </td>
                  <td style={styles.td}>
                    <div style={styles.actions}>
                      <button 
                        onClick={() => handleEdit(place)} 
                        style={styles.editButton}
                      >
                        Edit
                      </button>
                      <button 
                        onClick={() => handleDelete(place.id)} 
                        style={styles.deleteButton}
                      >
                        Delete
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

